#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/wait.h>
#include <signal.h>

static volatile sig_atomic_t found = 0;
static unsigned char found_buf[16];
static int found_n = 0;

static int try_one(const unsigned char *buf, int n, const char *exp, int expn) {
    int in[2], out[2];
    if (pipe(in) || pipe(out)) return 0;
    pid_t pid = fork();
    if (pid == 0) {
        dup2(in[0], 0);
        dup2(out[1], 1);
        close(in[0]); close(in[1]); close(out[0]); close(out[1]);
        execl("/app/decomp", "decomp", (char*)0);
        _exit(127);
    }
    close(in[0]); close(out[1]);
    ssize_t w = write(in[1], buf, n);
    close(in[1]);
    if (w != n) { close(out[0]); waitpid(pid, 0, 0); return 0; }
    unsigned char obuf[10000];
    int got = 0, r;
    while ((r = read(out[0], obuf + got, sizeof(obuf) - got)) > 0) {
        got += r;
        if (got >= sizeof(obuf)) break;
    }
    close(out[0]);
    int status;
    waitpid(pid, &status, 0);
    if (!WIFEXITED(status) || WEXITSTATUS(status) != 0) return 0;
    return got == expn && memcmp(obuf, exp, expn) == 0;
}

int main(int argc, char **argv) {
    const char *exp = argc > 1 ? argv[1] : "A";
    int expn = strlen(exp);
    unsigned char buf[8];

    for (int n = 1; n <= 5; n++) {
        long total = 1;
        for (int i = 0; i < n; i++) total *= 256;
        fprintf(stderr, "trying n=%d total=%ld\n", n, total);
        fflush(stderr);
        for (long idx = 0; idx < total; idx++) {
            long x = idx;
            for (int i = 0; i < n; i++) { buf[i] = x & 0xFF; x >>= 8; }
            if (try_one(buf, n, exp, expn)) {
                printf("FOUND n=%d bytes:", n);
                for (int i = 0; i < n; i++) printf(" %02x", buf[i]);
                printf("\n");
                fflush(stdout);
                return 0;
            }
        }
    }
    printf("NOTFOUND\n");
    return 1;
}
